// src/components/Button.js

import React, { useState, useEffect } from 'react';
import axios from 'axios';

const Button = ({ label, onClick }) => {
  const [buttonStyle, setButtonStyle] = useState({});
  const [buttonText, setButtonText] = useState('');

  useEffect(() => {
    // Fetch Figma button data
    axios.get('http://localhost:3001/figma-data')
      .then(response => {
        const figmaData = response.data;
        const buttonComponent = figmaData.document.children[0].children[0].children[0];

        const fillColor = buttonComponent.children[0].fills[0].color;
        const textColor = buttonComponent.children[1].style;
        const text = buttonComponent.children[1].characters;
        const borderRadius = buttonComponent.children[0].cornerRadius;

        const newButtonStyle = {
          backgroundColor: `rgb(${fillColor.r * 255}, ${fillColor.g * 255}, ${fillColor.b * 255})`,
          color: `rgb(${textColor.color.r * 255}, ${textColor.color.g * 255}, ${textColor.color.b * 255})`,
          padding: '12px 24px',
          borderRadius: `${borderRadius}px`,
        };

        setButtonText(text);
        setButtonStyle(newButtonStyle);
      })
      .catch(error => {
        console.error('Error fetching Figma data:', error);
      });
  }, []);

  return (
    <button 
      style={buttonStyle} 
      onClick={onClick}>
      {buttonText || label}
    </button>
  );
};

export default Button;
